 1	import { type FC, useState } from 'react';
 2	import { getStorageMapFieldId } from 'src/storageMaps/utils/getStorageMapFieldId';
 3	
 4	import TechPreviewLabel from '@components/PreviewLabels/TechPreviewLabel';
 5	import type { V1beta1Provider } from '@kubev2v/types';
 6	import { ExpandableSection, Form, Split, SplitItem } from '@patternfly/react-core';
 7	import { useForkliftTranslation } from '@utils/i18n';
 8	
 9	import { StorageMapFieldId } from '../../constants';
10	
11	import OffloadPluginField from './OffloadPluginField';
12	import StorageProductField from './StorageProductField';
13	import StorageSecretField from './StorageSecretField';
14	
15	import './OffloadStorageIndexedForm.style.scss';
16	
17	type OffloadStorageIndexedFormProps = {
18	  index: number;
19	  sourceProvider: V1beta1Provider | undefined;
20	};
21	
22	const OffloadStorageIndexedForm: FC<OffloadStorageIndexedFormProps> = ({
23	  index,
24	  sourceProvider,
25	}) => {
26	  const { t } = useForkliftTranslation();
27	  const [isExpanded, setIsExpanded] = useState(false);
28	
29	  return (
30	    <ExpandableSection
31	      toggleContent={
32	        <Split hasGutter>
33	          <SplitItem>{t('Offload options (optional)')}</SplitItem>
34	          <SplitItem>
35	            <TechPreviewLabel />
36	          </SplitItem>
37	        </Split>
38	      }
39	      onToggle={(_e, expanded) => {
40	        setIsExpanded(expanded);
41	      }}
42	      isExpanded={isExpanded}
43	      isIndented
44	    >
45	      <Form className="offload-storage__form">
46	        <OffloadPluginField
47	          fieldId={getStorageMapFieldId(StorageMapFieldId.OffloadPlugin, index)}
48	        />
49	        <StorageSecretField
50	          fieldId={getStorageMapFieldId(StorageMapFieldId.StorageSecret, index)}
51	          sourceProvider={sourceProvider}
52	        />
53	        <StorageProductField
54	          fieldId={getStorageMapFieldId(StorageMapFieldId.StorageProduct, index)}
55	        />
56	      </Form>
57	    </ExpandableSection>
58	  );
59	};
60	
61	export default OffloadStorageIndexedForm;

